import java.io.*;import java.util.*;public class Main{    static final int MAXP=524300,B=100;    static ArrayList<Integer>pr=new ArrayList<>();    static boolean[]isp=new boolean[MAXP];    static void sieve(){        Arrays.fill(isp,true);        isp[0]=isp[1]=false;        for(int p=2;p<MAXP;p++)if(isp[p]){            pr.add(p);            for(int i=2*p;i<MAXP;i+=p)isp[i]=false;        }    }    static ArrayList<Long>G=new ArrayList<>();    static long sumf,tot;    static int[]diff=new int[524305];    static int m,M,lg;    static void getd(int idx,long d,int sgn){        sumf+=sgn;        if(d==1)tot+=sgn*(long)(m+1)*(m+1)*(m+1);        else if(d<=B){            Arrays.fill(diff,0,m+2,0);            for(int x=0;x<M;x+=d){                for(int b=lg-1;b>=0;b--)if(((m>>b)&1)==1){                    int P=(m>>(b+1))<<(b+1);                    int v=P^((x>>b)<<b);                    int L=Math.max(0,v),R=Math.min(m,v+(1<<b)-1);                    if(L<=R){diff[L]++;diff[R+1]--;}                }                int j=m^x;                if(j<=m){diff[j]++;diff[j+1]--;}            }            long ss=0,cur=0;            for(int j=0;j<=m;j++){cur+=diff[j];ss+=cur*cur;}            tot+=sgn*ss;        }else{            ArrayList<int[]>ev=new ArrayList<>();            for(int x=0;x<M;x+=d){                for(int b=lg-1;b>=0;b--)if(((m>>b)&1)==1){                    int P=(m>>(b+1))<<(b+1);                    int v=P^((x>>b)<<b);                    int L=Math.max(0,v),R=Math.min(m,v+(1<<b)-1);                    if(L<=R){ev.add(new int[]{L,1});ev.add(new int[]{R+1,-1});}                }                int j=m^x;                if(j<=m){ev.add(new int[]{j,1});ev.add(new int[]{j+1,-1});}            }            ev.sort(Comparator.comparingInt(a->a[0]));            long ss=0,cur=0;            int last=0,i=0;            while(i<ev.size()){                int X=ev.get(i)[0];                if(X>last){long len=X-last;ss+=cur*cur*len;}                while(i<ev.size()&&ev.get(i)[0]==X){cur+=ev.get(i)[1];i++;}                last=X;            }            tot+=sgn*ss;        }        for(int i=idx;i<G.size();i++){            if(d*G.get(i)<M)getd(i+1,d*G.get(i),-sgn);            else break;        }    }    static void solve(FS fs,PrintWriter out)throws Exception{        long n=fs.nl();        m=fs.ni();        M=1;while(M<=m)M<<=1;        lg=Integer.numberOfTrailingZeros(M);        ArrayList<long[]>fac=new ArrayList<>();        long tn=n;        for(int p:pr){            if(1L*p*p>tn)break;            if(tn%p==0){                int c=0;                while(tn%p==0){c++;tn/=p;}                fac.add(new long[]{p,c});            }        }        if(tn>1)fac.add(new long[]{tn,1});        G.clear();        int fi=0;        for(int p:pr){            if(p>=M)break;            long gp=p;            while(fi<fac.size()&&fac.get(fi)[0]<p)fi++;            if(fi<fac.size()&&fac.get(fi)[0]==p){                int vp=(int)fac.get(fi)[1];                gp=1;                for(int i=0;i<=vp;i++){gp*=p;if(gp>=M)break;}            }            if(gp<M)G.add(gp);        }        Collections.sort(G);        sumf=0;tot=0;        getd(0,1,1);        tot-=(long)(m+1)*sumf;        out.println(tot);    }    public static void main(String[]args)throws Exception{        FS fs=new FS();        PrintWriter out=new PrintWriter(System.out);        sieve();        int t=fs.ni();        while(t-->0)solve(fs,out);        out.flush();    }    static class FS{        BufferedReader br=new BufferedReader(new InputStreamReader(System.in));        StringTokenizer st;        String nx()throws Exception{            while(st==null||!st.hasMoreElements())st=new StringTokenizer(br.readLine());            return st.nextToken();        }        int ni()throws Exception{return Integer.parseInt(nx());}        long nl()throws Exception{return Long.parseLong(nx());}    }}